from minimarkdown import Markdown

def contains_type(value, target):
    if isinstance(value, dict):
        return value.get('type') == target or any(contains_type(v, target) for v in value.values())
    if isinstance(value, list):
        return any(contains_type(v, target) for v in value)
    return False

doc = '''> ## Inner *Head*
> quoted **text**
>
> - item [one](https://e.test)'''
html = Markdown()(doc)
ast = Markdown('ast')(doc)
quote = ast[0] if ast else {}
print(isinstance(quote, dict) and quote.get('type') == 'block_quote')
print(contains_type(quote, 'emphasis'), contains_type(quote, 'strong'), contains_type(quote, 'link'))
print('<h2 id="inner-head">Inner <em>Head</em></h2>' in html)
print('<li>item <a href="https://e.test">one</a></li>' in html)

from minimarkdown import Markdown

def plain(value):
    if isinstance(value, str):
        return value
    if isinstance(value, dict):
        if 'children' in value:
            return ''.join(plain(child) for child in value['children'])
        return value.get('text', '')
    if isinstance(value, list):
        return ''.join(plain(item) for item in value)
    return ''

def safe_toc(md, text):
    try:
        return md.toc(text)
    except Exception:
        return []

doc = '''# H

- *one*
- `two`

## H'''
html = Markdown()(doc)
ast = Markdown('ast')(doc)
toc = safe_toc(Markdown(), doc)
heads = [t for t in ast if isinstance(t, dict) and t.get('type') == 'heading']
lists = [t for t in ast if isinstance(t, dict) and t.get('type') == 'list']
item_texts = [plain(item) for item in (lists[0].get('items', []) if lists else [])]
print([h.get('attrs', {}).get('id') for h in heads] == [entry.get('id') for entry in toc] == ['h', 'h-2'])
print(item_texts == ['one', 'two'])
print('<h1 id="h">H</h1>' in html, '<em>one</em>' in html, '<code>two</code>' in html, '<h2 id="h-2">H</h2>' in html)

from minimarkdown import Markdown

def count_type(value, target):
    if isinstance(value, dict):
        return (1 if value.get('type') == target else 0) + sum(count_type(v, target) for v in value.values())
    if isinstance(value, list):
        return sum(count_type(v, target) for v in value)
    return 0

doc = '''Para ~~*gone*~~.

- keep ~~**this**~~'''
html = Markdown(plugins=['strikethrough'])(doc)
ast = Markdown('ast', plugins=['strikethrough'])(doc)
print(count_type(ast, 'strikethrough') == 2)
print('<p>Para <del><em>gone</em></del>.</p>' in html)
print('<li>keep <del><strong>this</strong></del></li>' in html)

