from minimarkdown import Markdown

def count_type(value, target):
    if isinstance(value, dict):
        return (1 if value.get('type') == target else 0) + sum(count_type(v, target) for v in value.values())
    if isinstance(value, list):
        return sum(count_type(v, target) for v in value)
    return 0

doc = '''- [x] **Done**
- [ ] [Todo](https://e.test)'''
html = Markdown(plugins=['task_list'])(doc)
ast = Markdown('ast', plugins=['task_list'])(doc)
items = ast[0].get('items', []) if ast and isinstance(ast[0], dict) else []
print([item.get('checked') for item in items] == [True, False])
print(count_type(items, 'strong') == 1, count_type(items, 'link') == 1)
print('<input type="checkbox" disabled checked> <strong>Done</strong>' in html)
print('<input type="checkbox" disabled> <a href="https://e.test">Todo</a>' in html)

from minimarkdown import Markdown, escape_html

def badge_plugin(md):
    md.register_inline('badge', r'\[\[([^\]]+)\]\]', lambda m: {'text': m.group(1)}, lambda r, t: '<span class="badge">' + escape_html(t['text']) + '</span>')

def count_badges(value):
    if isinstance(value, dict):
        return (1 if value.get('type') == 'badge' and value.get('text') == 'v1 & beta' else 0) + sum(count_badges(v) for v in value.values())
    if isinstance(value, list):
        return sum(count_badges(v) for v in value)
    return 0

try:
    html = Markdown(plugins=[badge_plugin])('Ship [[v1 & beta]]')
    ast = Markdown('ast', plugins=[badge_plugin])('Ship [[v1 & beta]]')
except Exception:
    html = ''
    ast = []
print(html == '<p>Ship <span class="badge">v1 &amp; beta</span></p>')
print(count_badges(ast) == 1)

